parameters.jsCode:
// Analyze pipeline and generate daily briefing
const deals = $input.all();

const pipeline = {
  hotLeads: [],
  warmLeads: [],
  meetingsScheduled: [],
  proposalsSent: [],
  negotiating: [],
  staleDeals: []
};

const now = new Date();

deals.forEach(deal => {
  const f = deal.json.fields || {};
  const status = f['Lead Status'] || '';
  const lastActivity = f['Reply Date'] || f['Email 1 Sent At'] || f['Scraped At'];
  const daysSinceActivity = lastActivity ? 
    Math.floor((now - new Date(lastActivity)) / (1000 * 60 * 60 * 24)) : 999;

  const dealSummary = {
    id: deal.json.id,
    company: f['Company Name'],
    phone: f['Phone'],
    email: f['Verified Email'],
    status: status,
    intentScore: f['Intent Score'] || 0,
    proposedMonthly: f['Proposed Monthly'] || 0,
    meetingTime: f['Meeting Time'],
    daysSinceActivity: daysSinceActivity,
    action: f['Recommended Action'] || 'follow_up'
  };

  // Categorize
  if (status === 'Hot Lead') pipeline.hotLeads.push(dealSummary);
  else if (status === 'Warm Lead') pipeline.warmLeads.push(dealSummary);
  else if (status === 'Meeting Scheduled') pipeline.meetingsScheduled.push(dealSummary);
  else if (status === 'Proposal Sent') pipeline.proposalsSent.push(dealSummary);
  else if (status === 'Negotiating') pipeline.negotiating.push(dealSummary);

  // Flag stale deals (no activity in 5+ days)
  if (daysSinceActivity >= 5 && status !== 'Meeting Scheduled') {
    pipeline.staleDeals.push(dealSummary);
  }
});

// Calculate pipeline value
const pipelineValue = deals.reduce((sum, d) => {
  const monthly = d.json.fields?.['Proposed Monthly'] || 497;
  return sum + (monthly * 12); // Annual value
}, 0);

// Today's priorities
const todaysPriorities = [
  ...pipeline.hotLeads.slice(0, 3),
  ...pipeline.proposalsSent.filter(d => d.daysSinceActivity >= 2).slice(0, 2),
  ...pipeline.staleDeals.slice(0, 2)
].slice(0, 5);

return {
  json: {
    date: now.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' }),
    totalDeals: deals.length,
    pipelineValue: pipelineValue,

    counts: {
      hotLeads: pipeline.hotLeads.length,
      warmLeads: pipeline.warmLeads.length,
      meetings: pipeline.meetingsScheduled.length,
      proposals: pipeline.proposalsSent.length,
      negotiating: pipeline.negotiating.length,
      stale: pipeline.staleDeals.length
    },

    todaysPriorities: todaysPriorities,
    todaysMeetings: pipeline.meetingsScheduled.filter(m => {
      if (!m.meetingTime) return false;
      const meetingDate = new Date(m.meetingTime).toDateString();
      return meetingDate === now.toDateString();
    }),

    staleDeals: pipeline.staleDeals,
    pipeline: pipeline
  }
};

