// Generate re-engagement actions for stale deals
const pipeline = $input.first().json;
const staleDeals = pipeline.staleDeals || [];

return staleDeals.map(deal => ({
  json: {
    dealId: deal.id,
    company: deal.company,
    phone: deal.phone,
    email: deal.email,
    daysSinceActivity: deal.daysSinceActivity,
    currentStatus: deal.status,
    suggestedAction: deal.daysSinceActivity > 10 ? 'breakup_email' : 'phone_call'
  }
}));

// Calculate today's performance
const wins = $input.all();

const totalWonValue = wins.reduce((sum, w) => {
  const monthly = w.json.fields?.['Proposed Monthly'] || 497;
  return sum + monthly;
}, 0);

const wonCompanies = wins.map(w => w.json.fields?.['Company Name']).filter(Boolean);

return {
  json: {
    winsToday: wins.length,
    totalMRR: totalWonValue,
    annualValue: totalWonValue * 12,
    companies: wonCompanies
  }
};

